namespace sv_ca77aa48b4c94c588da39a68cb2956da.Client.Models;

public sealed class Shipment
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public DateTimeOffset? EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required string Description { get; init; }
    public required string Location { get; init; }
    public required DateTimeOffset Timestamp { get; init; }
}

using sv_ca77aa48b4c94c588da39a68cb2956da.Client.Models;

namespace sv_ca77aa48b4c94c588da39a68cb2956da.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_ca77aa48b4c94c588da39a68cb2956da.Client.Models;
using sv_ca77aa48b4c94c588da39a68cb2956da.Client.Services;

namespace sv_ca77aa48b4c94c588da39a68cb2956da.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> Seeds = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new Shipment
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 2, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "New York, NY", Timestamp = new DateTimeOffset(2026, 5, 25, 9, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Departed facility", Location = "New York, NY", Timestamp = new DateTimeOffset(2026, 5, 25, 14, 30, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Arrived at hub", Location = "Chicago, IL", Timestamp = new DateTimeOffset(2026, 5, 26, 6, 15, 0, TimeSpan.Zero) },
            ]
        },
        ["PKG-002"] = new Shipment
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 24, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Seattle, WA", Timestamp = new DateTimeOffset(2026, 5, 20, 10, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "In transit", Location = "Portland, OR", Timestamp = new DateTimeOffset(2026, 5, 21, 8, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Out for delivery", Location = "San Francisco, CA", Timestamp = new DateTimeOffset(2026, 5, 24, 7, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Delivered", Location = "San Francisco, CA", Timestamp = new DateTimeOffset(2026, 5, 24, 11, 45, 0, TimeSpan.Zero) },
            ]
        },
        ["PKG-003"] = new Shipment
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Miami, FL",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 5, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Location = "Miami, FL", Timestamp = new DateTimeOffset(2026, 5, 27, 8, 0, 0, TimeSpan.Zero) },
            ]
        },
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        Seeds.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using System.Net.Http.Json;
using sv_ca77aa48b4c94c588da39a68cb2956da.Client.Models;

namespace sv_ca77aa48b4c94c588da39a68cb2956da.Client.Services;

/// <summary>
/// HTTP-based implementation used when running on WebAssembly.
/// Calls the server API to fetch shipment data.
/// </summary>
public sealed class ShipmentServiceClient(HttpClient http) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var encoded = Uri.EscapeDataString(trackingNumber);
        var response = await http.GetAsync($"api/shipments/{encoded}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_ca77aa48b4c94c588da39a68cb2956da.Client.Models
@using sv_ca77aa48b4c94c588da39a68cb2956da.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="shipment-loading">
        <p><em>Loading shipment details for @TrackingNumber…</em></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="shipment-error">
        <p>@_errorMessage</p>
        <button @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="shipment-not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            @if (_shipment.EstimatedDelivery.HasValue)
            {
                <dt>Estimated Delivery</dt>
                <dd>@_shipment.EstimatedDelivery.Value.ToString("f")</dd>
            }
        </dl>

        <h3>Tracking History</h3>
        <table>
            <thead>
                <tr>
                    <th>Time</th>
                    <th>Location</th>
                    <th>Description</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in _shipment.StatusUpdates)
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Location</td>
                        <td>@update.Description</td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override Task OnParametersSetAsync() => LoadShipmentAsync();

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request when the tracking number changes or on retry
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _shipment = null;
        _errorMessage = null;
        _loading = true;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — silently abandon
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private Task RetryAsync() => LoadShipmentAsync();

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

