@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_ca77aa48b4c94c588da39a68cb2956da.Client.Models
@using sv_ca77aa48b4c94c588da39a68cb2956da.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="shipment-loading">
        <p><em>Loading shipment details for @TrackingNumber…</em></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="shipment-error">
        <p>@_errorMessage</p>
        <button @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="shipment-not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            @if (_shipment.EstimatedDelivery.HasValue)
            {
                <dt>Estimated Delivery</dt>
                <dd>@_shipment.EstimatedDelivery.Value.ToString("f")</dd>
            }
        </dl>

        <h3>Tracking History</h3>
        <table>
            <thead>
                <tr>
                    <th>Time</th>
                    <th>Location</th>
                    <th>Description</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in _shipment.StatusUpdates)
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Location</td>
                        <td>@update.Description</td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override Task OnParametersSetAsync() => LoadShipmentAsync();

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request when the tracking number changes or on retry
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _shipment = null;
        _errorMessage = null;
        _loading = true;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — silently abandon
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading the shipment. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private Task RetryAsync() => LoadShipmentAsync();

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

